import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";

let cachedStatus: any = null;
let lastFetched = 0;
const CACHE_TTL = 15000; // 15 seconds cache duration

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Middleware
  app.use(express.json());

  // Minecraft server status endpoint
  app.get("/api/minecraft-status", async (req, res) => {
    const now = Date.now();
    if (cachedStatus && (now - lastFetched < CACHE_TTL)) {
      return res.json(cachedStatus);
    }

    try {
      // Fetch status from mcsrvstat.us for slarof.ru
      const response = await fetch("https://api.mcsrvstat.us/3/slarof.ru", {
        signal: AbortSignal.timeout(4000),
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      
      // If it says offline, try fallback domain mc.slarof.ru
      if (!data.online) {
        const fallbackResponse = await fetch("https://api.mcsrvstat.us/3/mc.slarof.ru", {
          signal: AbortSignal.timeout(4000),
        });
        if (fallbackResponse.ok) {
          const fallbackData = await fallbackResponse.json();
          if (fallbackData.online) {
            cachedStatus = fallbackData;
            lastFetched = now;
            return res.json(fallbackData);
          }
        }
      }

      cachedStatus = data;
      lastFetched = now;
      res.json(data);
    } catch (error: any) {
      console.error("Error fetching Minecraft status:", error.message);
      // Return stale cache if available, or a generic offline state
      if (cachedStatus) {
        return res.json(cachedStatus);
      }
      res.json({
        online: false,
        ip: "slarof.ru",
        port: 25565,
        hostname: "slarof.ru",
        players: {
          online: 0,
          max: 100
        },
        version: "26.2",
        motd: {
          clean: ["Приватный ванильный сервер Слароф", "Сервер временно оффлайн или обновляется"]
        }
      });
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://0.0.0.0:${PORT}`);
  });
}

startServer();
